export const Button = ({
  isLoading, isPrimary, isOutline, isSmall, hasIcon, isDisabled, children
}: {
  isLoading?: boolean; isPrimary?: boolean; isOutline?: boolean
  isSmall?: boolean; hasIcon?: boolean; isDisabled?: boolean
  children: React.ReactNode
}) => {
  return (
    <button
      disabled={isDisabled || isLoading}
      className={cn(
        'px-4 py-2',
        isPrimary && 'bg-primary text-white',
        isOutline && 'border bg-transparent',
        isSmall && 'px-2 py-1 text-sm'
      )}
    >
      {isLoading ? 'Loading...' : children}
    </button>
  )
}

import { cn } from '@/lib/utils'

type Variant = 'primary' | 'outline' | 'ghost'
type Size = 'sm' | 'md' | 'lg'

export const Button = ({
  variant = 'primary', size = 'md', className, children, ...props
}: {
  variant?: Variant
  size?: Size
  className?: string
  children: React.ReactNode
} & React.ComponentProps<'button'>) => {
  return (
    <button
      className={cn(
        'rounded font-medium',
        variant === 'primary' && 'bg-primary text-white',
        variant === 'outline' && 'border bg-transparent',
        size === 'sm' && 'px-2 py-1 text-sm',
        size === 'md' && 'px-4 py-2',
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

